head.script:
/**/
tailwind.config = {
  darkMode: ['class', '[data-theme="dark"]'],
  theme: {
    extend: {
      colors: {
        primary: { DEFAULT: '#FF6A1A', 50:'#FFF3EC',100:'#FFE0CC',200:'#FFC299',300:'#FFA266',400:'#FF8B3D',500:'#FF6A1A',600:'#E05500',700:'#B34400',800:'#803000',900:'#4D1D00' },
        cyan: { DEFAULT:'#00B7E5',50:'#E6FAFF',100:'#B3F0FF',200:'#80E6FF',300:'#4DDBFF',400:'#1AD1FF',500:'#00B7E5',600:'#0093B8',700:'#006F8A' },
        gold: '#E0A500',
        dark: '#0a0a0a',
        bg: 'rgb(var(--c-bg) / <alpha-value>)',
        'bg-2': 'rgb(var(--c-bg-2) / <alpha-value>)',
        surface: 'rgb(var(--c-surface-soft) / <alpha-value>)',
        'surface-hover': 'rgb(var(--c-surface-hover) / <alpha-value>)',
        line: 'rgb(var(--c-line) / <alpha-value>)',
        fg: 'rgb(var(--c-fg) / <alpha-value>)',
        'fg-muted': 'rgb(var(--c-fg-muted) / <alpha-value>)',
        'fg-soft': 'rgb(var(--c-fg-soft) / <alpha-value>)',
      },
      fontFamily: {
        display: ['Orbitron','sans-serif'],
        headline: ['Orbitron','sans-serif'],
        body: ['Inter','sans-serif'],
        racing: ['Rajdhani','sans-serif'],
        ui: ['Rajdhani','sans-serif'],
        sora: ['Sora','sans-serif'],
      },
    },
  },
};
/**/

body.script:
/**/
(function(){
  var d = document;
  var $ = function(sel, root){ return (root||d).querySelector(sel); };
  var $$ = function(sel, root){ return Array.prototype.slice.call((root||d).querySelectorAll(sel)); };

  // ---- Theme persistence ----
  var THEME_KEY = 'sb-theme';
  function applyTheme(t){
    d.documentElement.setAttribute('data-theme', t);
    if (t === 'dark') d.documentElement.classList.add('dark');
    else d.documentElement.classList.remove('dark');
    var sun = $('.sb-theme-icon-sun');
    var moon = $('.sb-theme-icon-moon');
    if (sun && moon){
      if (t === 'dark'){ sun.removeAttribute('hidden'); moon.setAttribute('hidden','hidden'); }
      else { moon.removeAttribute('hidden'); sun.setAttribute('hidden','hidden'); }
    }
  }
  try { applyTheme(localStorage.getItem(THEME_KEY) || 'light'); } catch(e){ applyTheme('light'); }
  function toggleTheme(){
    var cur = d.documentElement.getAttribute('data-theme') || 'light';
    var next = cur === 'dark' ? 'light' : 'dark';
    try { localStorage.setItem(THEME_KEY, next); } catch(e){}
    applyTheme(next);
  }
  d.addEventListener('click', function(ev){
    var t = ev.target.closest && ev.target.closest('#sb-theme-toggle, #sb-theme-toggle-mobile');
    if (t){ ev.preventDefault(); toggleTheme(); }
  });

  // ---- Page loader hide ----
  function hideLoader(){
    var l = $('#sb-page-loader');
    if (l) { l.classList.add('hide'); setTimeout(function(){ if (l.parentNode) l.parentNode.removeChild(l); }, 700); }
  }
  if (d.readyState === 'complete') setTimeout(hideLoader, 380);
  else window.addEventListener('load', function(){ setTimeout(hideLoader, 380); });

  // ---- Mobile drawer ----
  var drawer = $('#sb-mobile-drawer'), backdrop = $('#sb-mobile-backdrop');
  function openDrawer(){ if(drawer){ drawer.classList.add('open'); } if(backdrop){ backdrop.classList.add('open'); } d.body.style.overflow = 'hidden'; }
  function closeDrawer(){ if(drawer){ drawer.classList.remove('open'); } if(backdrop){ backdrop.classList.remove('open'); } d.body.style.overflow = ''; }
  d.addEventListener('click', function(ev){
    var t = ev.target;
    if (t.closest && t.closest('#sb-mobile-menu-btn, #sb-mobile-more-btn')){ ev.preventDefault(); openDrawer(); }
    if (t.closest && (t.closest('[data-close-sheet]') || t.closest('#sb-mobile-backdrop'))){ closeDrawer(); }
  });

  // ---- Search overlay ----
  var searchOverlay = $('#sb-search-overlay');
  function openSearch(){ if(searchOverlay){ searchOverlay.classList.add('open'); var inp = searchOverlay.querySelector('input'); if(inp){ setTimeout(function(){ inp.focus(); }, 80); } } }
  function closeSearch(){ if(searchOverlay){ searchOverlay.classList.remove('open'); } }
  d.addEventListener('click', function(ev){
    var t = ev.target;
    if (t.closest && t.closest('#sb-nav-search, #sb-mobile-search-btn')){ ev.preventDefault(); openSearch(); }
    if (t.closest && t.closest('#sb-search-close')){ closeSearch(); }
  });
  d.addEventListener('keydown', function(ev){ if (ev.key === 'Escape'){ closeSearch(); closeDrawer(); } });

  // ---- FAQ accordion ----
  d.addEventListener('click', function(ev){
    var btn = ev.target.closest && ev.target.closest('[data-faq-trigger]');
    if (!btn) return;
    ev.preventDefault();
    var card = btn.closest('.sb-faq-card');
    if (card) card.classList.toggle('open');
  });

  // ---- Reveal animations ----
  function bindReveals(root){
    var els = $$('.v-reveal', root || d);
    if (!('IntersectionObserver' in window)){
      els.forEach(function(el){ el.classList.add('in'); });
      return;
    }
    var io = new IntersectionObserver(function(entries){
      entries.forEach(function(e){
        if (e.isIntersecting){ e.target.classList.add('in'); io.unobserve(e.target); }
      });
    }, { threshold: 0.12, rootMargin: '0px 0px -40px 0px' });
    els.forEach(function(el){ io.observe(el); });
  }
  bindReveals();

  // ---- Active mobile dock highlight ----
  (function(){
    var p = location.pathname;
    var key = 'home';
    if (/\/search\/label\/product/.test(p)) key = 'shop';
    else if (/categories\.html/.test(p)) key = 'cats';
    else if (/checkout\.html/.test(p)) key = 'cart';
    var el = d.querySelector('[data-mobile-tab="' + key + '"]');
    if (el) el.classList.add('is-active');
  })();

  // ---- Product feed fetch (homepage only) ----
  function escapeHtml(s){ return String(s||'').replace(/[&<>"']/g, function(c){ return ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c]; }); }
  function extractMeta(content){
    // Look for hidden product meta JSON in post body
    var m = content && content.match(/<pre[^>]*class=["'][^"']*sb-product-meta-raw[^"']*["'][^>]*>([\s\S]*?)<\/pre>/i);
    if (!m) return {};
    try { var json = m[1].replace(/&quot;/g,'"').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&amp;/g,'&'); return JSON.parse(json); } catch(e){ return {}; }
  }
  function extractFirstImg(content){
    var m = content && content.match(/<img[^>]+src=["']([^"']+)["']/i);
    return m ? m[1] : '';
  }
  function badgeOf(meta){
    if (meta.badge) return meta.badge;
    if (meta.discount && Number(meta.discount) > 0) return Number(meta.discount) + '% OFF';
    return '';
  }
  function priceHtml(meta){
    var price = meta.price ? Number(meta.price) : 0;
    var was = meta.was || (meta.discount && price ? Math.round(price / (1 - Number(meta.discount)/100)) : 0);
    var out = '<span class="v-price-now">BDT ' + price.toLocaleString() + '</span>';
    if (was && was > price) out += ' <span class="v-price-old">BDT ' + Number(was).toLocaleString() + '</span>';
    return out;
  }
  function renderCard(post){
    var title = (post.title && post.title.$t) || 'Product';
    var content = (post.content && post.content.$t) || (post.summary && post.summary.$t) || '';
    var meta = extractMeta(content);
    var img = meta.image || (post['media$thumbnail'] && post['media$thumbnail'].url) || extractFirstImg(content) || 'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 400 400"><rect fill="%23f3f3f5" width="400" height="400"/></svg>';
    if (img.indexOf('s72-c') !== -1) img = img.replace(/\/s72(-c)?\//, '/s640/').replace(/=s72(-c)?/, '=s640');
    // post URL
    var url = '#';
    if (post.link){
      for (var i = 0; i < post.link.length; i++){ if (post.link[i].rel === 'alternate'){ url = post.link[i].href; break; } }
    }
    var badge = badgeOf(meta);
    var category = (post.category && post.category.length) ? (post.category.find(function(c){ return c.term !== 'product'; }) || {}).term || '' : '';
    return ''
      + '<a class="v-product-card group block relative" href="' + escapeHtml(url) + '">'
      +   '<button type="button" class="sb-wishlist-btn" aria-label="Wishlist" onclick="event.preventDefault();this.classList.toggle(\'is-on\');"><i data-lucide="heart" style="width:14px;height:14px"></i></button>'
      +   (badge ? '<span class="v-product-badge">' + escapeHtml(badge) + '</span>' : '')
      +   '<div class="v-product-media"><img loading="lazy" src="' + escapeHtml(img) + '" alt="' + escapeHtml(title) + '"/></div>'
      +   '<div class="v-product-body">'
      +     (category ? '<div class="v-eyebrow text-[10px]">' + escapeHtml(category) + '</div>' : '')
      +     '<h3 class="v-product-title">' + escapeHtml(title) + '</h3>'
      +     '<div class="v-stars mt-1">'
      +       '<i data-lucide="star" style="width:13px;height:13px;fill:#ff8a3a;color:#ff8a3a"></i>'
      +       '<i data-lucide="star" style="width:13px;height:13px;fill:#ff8a3a;color:#ff8a3a"></i>'
      +       '<i data-lucide="star" style="width:13px;height:13px;fill:#ff8a3a;color:#ff8a3a"></i>'
      +       '<i data-lucide="star" style="width:13px;height:13px;fill:#ff8a3a;color:#ff8a3a"></i>'
      +       '<i data-lucide="star" style="width:13px;height:13px;fill:#ff8a3a;color:#ff8a3a"></i>'
      +       '<span class="ml-1 text-[11px] text-fg-soft">4.9</span>'
      +     '</div>'
      +     '<div class="v-price-row mt-2">' + priceHtml(meta) + '</div>'
      +   '</div>'
      + '</a>';
  }
  function loadProducts(){
    var grid = $('#sb-featured-grid');
    if (!grid) return;
    var url = '/feeds/posts/default/-/product?alt=json&max-results=8';
    var s = d.createElement('script');
    var cb = 'sbFeedCB_' + Date.now();
    window[cb] = function(data){
      try {
        var entries = (data && data.feed && data.feed.entry) || [];
        if (!entries.length){
          grid.innerHTML = '<div class="col-span-full text-center text-fg-muted py-10 font-racing text-sm uppercase tracking-widest">No products yet. Add a post with label "product" in Blogger.</div>';
          return;
        }
        grid.innerHTML = entries.map(renderCard).join('');
        if (window.lucide && window.lucide.createIcons) window.lucide.createIcons();
      } catch(e){ console.error(e); }
    };
    s.src = url + '&callback=' + cb;
    s.async = true;
    d.body.appendChild(s);
  }
  if ($('#sb-featured-grid')) loadProducts();

  // ---- Product detail post: extract meta, hide raw block, render price/stock/gallery ----
  function hydrateProductDetail(){
    var body = $('#sb-product-body');
    if (!body) return;
    var rawEl = body.querySelector('pre.sb-product-meta-raw, pre[class*="sb-product-meta-raw"]');
    var meta = {};
    if (rawEl){
      try { meta = JSON.parse(rawEl.textContent); } catch(e){}
      rawEl.style.display = 'none';
    }
    if (meta.price){
      var p = $('#sb-prod-price'); if (p) p.textContent = 'BDT ' + Number(meta.price).toLocaleString();
    }
    var wasVal = meta.was || (meta.discount && meta.price ? Math.round(Number(meta.price) / (1 - Number(meta.discount)/100)) : 0);
    if (wasVal && Number(wasVal) > Number(meta.price)){
      var w = $('#sb-prod-price-was'); if (w){ w.textContent = 'BDT ' + Number(wasVal).toLocaleString(); w.removeAttribute('hidden'); }
    }
    var stockEl = $('#sb-prod-stock');
    if (stockEl){
      if (meta.stock === false || meta.stock === 'out' || meta.stock === 0){ stockEl.textContent = 'Out of stock'; stockEl.classList.add('text-red-500'); }
      else { stockEl.textContent = 'In Stock'; }
    }
    if (meta.short){
      var sd = $('#sb-prod-short-desc'); if (sd) sd.textContent = meta.short;
    }
    // Gallery thumbnails
    var gallery = (meta.images && meta.images.length) ? meta.images : [];
    var mainImg = $('#sb-prod-main-img img');
    if (!gallery.length && mainImg) gallery = [mainImg.getAttribute('src')];
    var thumbs = $('#sb-prod-thumbs');
    if (thumbs && gallery.length){
      thumbs.innerHTML = gallery.map(function(src, i){
        return '<div class="sb-prod-thumb ' + (i===0 ? 'active' : '') + '" data-thumb="' + i + '"><img loading="lazy" src="' + src + '" alt=""/></div>';
      }).join('');
      thumbs.addEventListener('click', function(ev){
        var t = ev.target.closest && ev.target.closest('[data-thumb]');
        if (!t) return;
        var i = +t.getAttribute('data-thumb');
        if (mainImg) mainImg.setAttribute('src', gallery[i]);
        thumbs.querySelectorAll('.sb-prod-thumb').forEach(function(el){ el.classList.remove('active'); });
        t.classList.add('active');
      });
    }
  }
  hydrateProductDetail();

  // ---- Lucide icons init ----
  if (window.lucide && window.lucide.createIcons){
    try { window.lucide.createIcons(); } catch(e){}
  } else {
    window.addEventListener('load', function(){ if (window.lucide && window.lucide.createIcons) try { window.lucide.createIcons(); } catch(e){} });
  }
})();
/**/
